def gen(rng, size):
    n = max(1, size)
    parts = [str(rng.randint(0, 999))]
    for _ in range(n - 1):
        op = rng.choice(['+', '-', '*', '/'])
        val = rng.randint(0, 999)
        if op == '/':
            val = rng.randint(1, 999)
        parts.append(op)
        parts.append(str(val))
    out = []
    for tok in parts:
        out.append(tok)
        if rng.random() < 0.3:
            out.append(' ')
    return [''.join(out)]

