class Solution:
    def calculate(self, s):
        tokens = []
        i = 0
        while i < len(s):
            c = s[i]
            if c == ' ':
                i += 1
            elif c.isdigit():
                j = i
                while j < len(s) and s[j].isdigit():
                    j += 1
                tokens.append(int(s[i:j]))
                i = j
            else:
                tokens.append(c)
                i += 1
        vals = [tokens[0]]
        ops_out = []
        k = 1
        while k < len(tokens):
            op = tokens[k]
            rhs = tokens[k + 1]
            if op in ('*', '/'):
                a = vals.pop()
                if op == '*':
                    vals.append(a * rhs)
                else:
                    vals.append(int(a / rhs))
            else:
                ops_out.append(op)
                vals.append(rhs)
            k += 2
        result = vals[0]
        for idx, op in enumerate(ops_out):
            if op == '+':
                result += vals[idx + 1]
            else:
                result -= vals[idx + 1]
        return result

