class Solution:
    def calculate(self, s):
        stack = []
        num = 0
        op = '+'
        s = s + '+'
        for c in s:
            if c == ' ':
                continue
            if c.isdigit():
                num = num * 10 + int(c)
            else:
                if op == '+':
                    stack.append(num)
                elif op == '-':
                    stack.append(-num)
                elif op == '*':
                    stack.append(stack.pop() * num)
                else:
                    top = stack.pop()
                    stack.append(int(top / num))
                op = c
                num = 0
        return sum(stack)

